CREATE TABLE IF NOT EXISTS `api_quota_tracker` (
  `id` int AUTO_INCREMENT NOT NULL,
  `date` varchar(10) NOT NULL,
  `requestsUsed` int NOT NULL DEFAULT 0,
  `quotaLimit` int NOT NULL DEFAULT 100,
  `lastUpdated` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `api_quota_tracker_id` PRIMARY KEY(`id`),
  CONSTRAINT `api_quota_tracker_date_unique` UNIQUE(`date`)
);

CREATE TABLE IF NOT EXISTS `api_sync_log` (
  `id` int AUTO_INCREMENT NOT NULL,
  `syncType` enum('fixtures','results','manual') NOT NULL,
  `status` enum('success','error','partial','skipped') NOT NULL,
  `leagueId` int NOT NULL,
  `season` int NOT NULL,
  `requestsUsed` int NOT NULL DEFAULT 0,
  `gamesCreated` int NOT NULL DEFAULT 0,
  `gamesUpdated` int NOT NULL DEFAULT 0,
  `resultsApplied` int NOT NULL DEFAULT 0,
  `errorMessage` text,
  `circuitBreakerTripped` boolean NOT NULL DEFAULT false,
  `triggeredBy` enum('cron','manual') NOT NULL DEFAULT 'cron',
  `triggeredByUserId` int,
  `durationMs` int,
  `createdAt` timestamp NOT NULL DEFAULT (now()),
  CONSTRAINT `api_sync_log_id` PRIMARY KEY(`id`)
);

ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballKey` varchar(64);
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballEnabled` boolean DEFAULT false NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballQuotaLimit` int DEFAULT 100 NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballSyncFixtures` boolean DEFAULT true NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballSyncResults` boolean DEFAULT true NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballLeagueId` int DEFAULT 1 NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballSeason` int DEFAULT 2026 NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballLastSync` timestamp;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballCircuitOpen` boolean DEFAULT false NOT NULL;
ALTER TABLE `platform_settings` ADD COLUMN IF NOT EXISTS `apiFootballCircuitOpenAt` timestamp;

